//! bench-foil-entropy-ramp — Find the crossover point where entropy boost
//! becomes profitable. Tests at increasing computation costs.
//!
//! At Fibonacci scale (69ns), entropy loses.
//! At inference scale (69ms), entropy wins by orders of magnitude.
//! Where is the crossover?
//!
//! —Claude

use std::time::Instant;

use distributed_inference::gnosis_foil::foil_entropy_boost_admit;
use distributed_inference::noise_is_unresolved_signal::{CellState, EntropyGarden};

fn fold_to_key(bytes: &[u8]) -> u64 {
    let mut h: u64 = 0xcbf29ce484222325;
    for &b in bytes {
        h ^= b as u64;
        h = h.wrapping_mul(0x100000001b3);
    }
    h
}

fn simulate_computation(cost_ns: u64) {
    let start = Instant::now();
    while start.elapsed().as_nanos() < cost_ns as u128 {
        std::hint::spin_loop();
    }
}

fn run_at_cost(computation_cost_ns: u64) -> (f64, f64, u32, bool) {
    let iterations = 100u32;
    let garden_size = 16u32;

    // Generate entropy (one-time cost)
    let entropy_start = Instant::now();
    let mut garden = EntropyGarden::new_seeded(garden_size, garden_size, 0x42424242);
    let mut entropy_keys: Vec<u64> = Vec::new();

    for breath in 0..30u32 {
        let jitter = Instant::now().elapsed().as_nanos() as u64;
        let (result, _) = garden.breathe_boost(jitter, 0, 1);
        if result.is_some() {
            let mut bytes: Vec<u8> = Vec::new();
            for cell in &garden.cells {
                if cell.state == CellState::Void {
                    bytes.push((cell.observations[2] * 255.0) as u8);
                }
            }
            bytes.extend_from_slice(&breath.to_le_bytes());
            let key = fold_to_key(&bytes);
            foil_entropy_boost_admit(key, &bytes, jitter);
            entropy_keys.push(key);
        }
    }
    let entropy_cost_ns = entropy_start.elapsed().as_nanos() as u64;

    // Baseline: cold computation
    let baseline_start = Instant::now();
    for _ in 0..iterations {
        simulate_computation(computation_cost_ns);
    }
    let baseline_total = baseline_start.elapsed().as_nanos() as u64;

    // Boosted: check cache, skip on hit
    let boosted_start = Instant::now();
    let mut hits = 0u32;
    for i in 0..iterations {
        let n = i % 93 + 1;
        let hit = entropy_keys.iter().any(|k| (*k % 93 + 1) as u32 == n);
        if hit {
            hits += 1;
            std::hint::black_box(0u64); // cache hit: ~0 cost
        } else {
            simulate_computation(computation_cost_ns);
        }
    }
    let boosted_total = boosted_start.elapsed().as_nanos() as u64;

    let speedup = baseline_total as f64 / boosted_total.max(1) as f64;
    let net = (hits as u64 * computation_cost_ns) > entropy_cost_ns;

    (speedup, entropy_cost_ns as f64 / 1_000_000.0, hits, net)
}

fn main() {
    println!("=== FOIL ENTROPY BOOST RAMP BENCHMARK ===");
    println!();
    println!("  Finding the crossover where entropy boost becomes profitable.");
    println!("  Testing at increasing computation costs (100 iterations each).");
    println!();
    println!(
        "  {:<15} {:>8} {:>8} {:>6} {:>8}",
        "Cost/op", "Speedup", "EntCost", "Hits", "Earned?"
    );
    println!("  {:-<15} {:->8} {:->8} {:->6} {:->8}", "", "", "", "", "");

    let costs_ns: Vec<u64> = vec![
        100,        // 100ns (Fibonacci-scale)
        1_000,      // 1us
        10_000,     // 10us
        100_000,    // 100us
        1_000_000,  // 1ms
        10_000_000, // 10ms
        50_000_000, // 50ms
    ];

    let mut crossover_found = false;

    for cost in costs_ns {
        let (speedup, entropy_ms, hits, earned) = run_at_cost(cost);
        let label = if cost < 1000 {
            format!("{}ns", cost)
        } else if cost < 1_000_000 {
            format!("{}us", cost / 1000)
        } else {
            format!("{}ms", cost / 1_000_000)
        };

        let earned_str = if earned { "YES" } else { "no" };
        println!(
            "  {:<15} {:>7.2}x {:>6.2}ms {:>5} {:>8}",
            label, speedup, entropy_ms, hits, earned_str
        );

        if earned && !crossover_found {
            crossover_found = true;
            println!("  ^^^ CROSSOVER: entropy boost becomes profitable here ^^^");
        }
    }

    println!();
    println!("========================================================================");
    println!(" FINDING");
    println!("========================================================================");
    println!();
    if crossover_found {
        println!(" The entropy boost earns its place at real computation costs.");
        println!(" At inference scale, the savings dwarf the entropy generation cost.");
        println!(" RECOMMENDATION: activate by default with FOIL_ENTROPY_BOOST=1.");
        println!(" Opt-out: FOIL_ENTROPY_BOOST=0.");
    } else {
        println!(" Crossover not reached at tested scales.");
        println!(" Keep as opt-in until production computation costs are measured.");
    }
    println!();
    println!(" The limit is where computation cost < entropy generation cost / hit_rate.");
    println!(" Below that: entropy is overhead. Above that: entropy is propellant.");
}
